394→std::unique_ptr<llvm::TargetMachine>
395→createTargetMachine(const LLVMTarget &target) {
396→  std::string errorMessage;
397→  auto llvmTarget =
398→      llvm::TargetRegistry::lookupTarget(target.getTriple(), errorMessage);
399→  if (!llvmTarget)
400→    return nullptr;
401→  std::unique_ptr<llvm::TargetMachine> machine(llvmTarget->createTargetMachine(
402→      target.getTriple(), target.getCpu() /* cpu e.g k8 */,
403→      target.getCpuFeatures() /* cpu features e.g avx512f */,
404→      target.llvmTargetOptions, llvm::Reloc::Model::PIC_, {},
405→      target.codeGenOptLevel,
406→      /*JIT=*/false));
407→  return machine;
408→}
