476→void LLVMCPUTargetCLOptions::bindOptions(OptionsBinder &binder) {
477→  // Initialize LLVM targets prior to the iree-llvmcpu-list-targets CLI opt.
478→  initializeLLVMTargets();
479→
480→  static llvm::cl::OptionCategory category("LLVMCPU HAL Target");
481→
482→  // General flags.
483→  binder.opt<bool>(
484→      "iree-llvmcpu-list-targets", listTargets, llvm::cl::cat(category),
485→      llvm::cl::desc("Lists all registered targets that the LLVM backend can "
486→                     "generate code for."),
487→      llvm::cl::ValueDisallowed, llvm::cl::callback([&](const bool &) {
488→        llvm::TargetRegistry::printRegisteredTargetsForVersion(llvm::outs());
489→        exit(0);
490→      }));
491→
492→  // Target invariant flags.
493→  binder.opt<std::string>(
494→      "iree-llvmcpu-system-linker-path", systemLinkerPath,
495→      llvm::cl::cat(category),
496→      llvm::cl::desc("Tool used to link system shared libraries produced by "
497→                     "IREE (for --iree-llvmcpu-link-embedded=false)."));
498→  binder.opt<std::string>(
499→      "iree-llvmcpu-embedded-linker-path", embeddedLinkerPath,
500→      llvm::cl::cat(category),
501→      llvm::cl::desc("Tool used to link embedded ELFs produced by IREE (for "
502→                     "--iree-llvmcpu-link-embedded=true)."));
503→  binder.opt<std::string>(
504→      "iree-llvmcpu-wasm-linker-path", wasmLinkerPath, llvm::cl::cat(category),
505→      llvm::cl::desc("Tool used to link WebAssembly modules produced by "
506→                     "IREE (for --iree-llvmcpu-target-triple=wasm32-*)."));
507→  binder.opt<bool>(
508→      "iree-llvmcpu-keep-linker-artifacts", keepLinkerArtifacts,
509→      llvm::cl::cat(category),
510→      llvm::cl::desc("Keep LLVM linker target artifacts (.so/.dll/etc)"));
511→
512→  // Default device options.
513→  binder.opt<std::string>("iree-llvmcpu-target-triple", targetTriple,
514→                          llvm::cl::cat(category),
515→                          llvm::cl::desc("LLVM target machine triple."));
